    let mut p_idx = 0;

    for i in 0..len {
        let current_ptr = unsafe { out_ptr.add(p_idx) };
        if current_ptr >= end {
            break;
        }

        unsafe {
            *current_ptr = fill as u8;
        }
        p_idx += 1;
    }

    unsafe {
        *out = std::slice::from_raw_parts_mut(out_ptr.add(p_idx), (*out).len() - p_idx);
