static void mi_out_alignright(char fill, char *start, size_t len, size_t extra, char *end)
{
  if ((len == 0) || (extra == 0))
  {
    return;
  }
  if (((start + len) + extra) >= end)
  {
    return;
  }
  for (size_t i = 1; i <= len; i += 1)
  {
    start[(len + extra) - i] = start[len - i];
  }

  for (size_t i = 0; i < extra; i += 1)
  {
    start[i] = fill;
  }

}

