static void mi_out_num(uintmax_t x, size_t base, char prefix, char **out, char *end)
{
  if (((x == 0) || (base == 0)) || (base > 16))
  {
    if (prefix != 0)
    {
      mi_outc(prefix, out, end);
    }
    mi_outc('0', out, end);
  }
  else
  {
    char *start = *out;
    while (x > 0)
    {
      char digit = (char) (x % base);
      mi_outc((digit <= 9) ? ('0' + digit) : (('A' + digit) - 10), out, end);
      x = x / base;
    }

    if (prefix != 0)
    {
      mi_outc(prefix, out, end);
    }
    size_t len = (*out) - start;
    for (size_t i = 0; i < (len / 2); i += 1)
    {
      char c = start[(len - i) - 1];
      start[(len - i) - 1] = start[i];
      start[i] = c;
    }

  }
}

mi_out_num.translated_code:
pub fn mi_out_num(x: u64, base: usize, prefix: char, out: &mut Option<&mut [u8]>, end: usize) {
    if x == 0 || base == 0 || base > 16 {
        if prefix != '\0' {
            mi_outc(prefix, out, end);
        }
        mi_outc('0', out, end);
    } else {
        let start_index = match out {
            Some(slice) => slice.len(),
            None => return,
        };

        let mut x_temp = x;
        while x_temp > 0 {
            let digit = (x_temp % base as u64) as u8;
            let c = if digit <= 9 {
                (b'0' + digit) as char
            } else {
                (b'A' + digit - 10) as char
            };
            mi_outc(c, out, end);
            x_temp /= base as u64;
        }

        if prefix != '\0' {
            mi_outc(prefix, out, end);
        }

        if let Some(slice) = out {
            let current_len = slice.len();
            let len = current_len - start_index;
            for i in 0..len / 2 {
                let left_idx = start_index + i;
                let right_idx = start_index + (len - i - 1);
                slice.swap(left_idx, right_idx);
            }
        }
    }
}

