        debug_assert!(
            arena_ref.start.load(Ordering::Relaxed) as usize % (1 << (9 + (13 + 3))) == 0,
            "(uintptr_t)mi_atomic_load_ptr_relaxed(uint8_t,&arena->start) % MI_SEGMENT_ALIGN == 0"
