bool _mi_prim_random_buf(void *buf, size_t buf_len)
{
  int flags = O_RDONLY;
  int fd = mi_prim_open("/dev/urandom", flags);
  if (fd < 0)
  {
    return 0;
  }
  size_t count = 0;
  while (count < buf_len)
  {
    ssize_t ret = mi_prim_read(fd, ((char *) buf) + count, buf_len - count);
    if (ret <= 0)
    {
      if ((errno != 11) && (errno != EINTR))
      {
        break;
      }
    }
    else
    {
      count += ret;
    }
  }

  mi_prim_close(fd);
  return count == buf_len;
}

_mi_prim_random_buf.translated_code:
pub fn _mi_prim_random_buf(buf: &mut [u8]) -> bool {
    let flags = libc::O_RDONLY;
    let fd_result = mi_prim_open(Some("/dev/urandom"), flags);

    let mut fd = match fd_result {
        Ok(file) => file,
        Err(_) => return false,
    };

    let buf_len = buf.len();
    let mut count = 0;

    while count < buf_len {
        let remaining = buf_len - count;
        let read_result = unsafe { 
            mi_prim_read(
                fd.as_raw_fd(), 
                buf[count..].as_mut_ptr() as *mut libc::c_void, 
                remaining
            ) 
        };

        if read_result > 0 {
            count += read_result as usize;
        } else if read_result == 0 {
            break; // EOF
        } else {
            // read_result < 0 indicates error
            let errno = std::io::Error::last_os_error().raw_os_error().unwrap_or(0);
            if errno != libc::EAGAIN && errno != libc::EINTR {
                break;
            }
        }
    }

    let _ = mi_prim_close(fd.as_raw_fd());
    count == buf_len
}

