    ctx->input[i + 4] = read32(key, i);
  }

  ctx->input[12] = 0;
  ctx->input[13] = 0;
  ctx->input[14] = (uint32_t) nonce;
  ctx->input[15] = (uint32_t) (nonce >> 32);
}

