fn rollback(
    bitmap: &[mi_bitmap_field_t],
    bitmap_fields: usize,
    idx: usize,
    count: usize,
    retries: usize,
    bitmap_idx: &mut Option<mi_bitmap_index_t>,
    initial_field: &mi_bitmap_field_t,
    initial_mask: usize,
) -> bool {
