    if _mi_bitmap_try_find_from_claim_across(
        bitmap,
        arena.field_count,
        idx,
        blocks,
        bitmap_idx,
    ) {
        if let Some(idx_val) = *bitmap_idx {
            arena
                .search_idx
                .store(mi_bitmap_index_field(idx_val), Ordering::Relaxed);
        }
        return true;
    }
    false
}

