static void mi_buffered_out(const char *msg, void *arg)
{
  buffered_t *buf = (buffered_t *) arg;
  if ((msg == 0) || (buf == 0))
  {
    return;
  }
  for (const char *src = msg; src[src_idx] != 0; src_idx += 1)
  {
    char c = src[src_idx];
    if (buf->used >= buf->count)
    {
      mi_buffered_flush(buf);
    }
    (buf->used < buf->count) ? ((void) 0) : (_mi_assert_fail("buf->used < buf->count", "/workdir/C2RustTranslation-main/subjects/mimalloc/src/stats.c", 294, __func__));
    buf->buf[buf->used++] = c;
    if (c == '\n')
    {
      mi_buffered_flush(buf);
    }
  }

  unsigned int src_idx = 0;
}

