        Some(p) => {
            // Convert Option<Box<MiBlockS>> to Option<Box<[u8]>>
            unsafe {
                // Convert Box<MiBlockS> to raw pointer, then to Box<[u8]>
                let ptr = Box::into_raw(p) as *mut u8;
                Some(Box::from_raw(std::ptr::slice_from_raw_parts_mut(ptr, size)))
