  }
  if ((hbuf->buf != 0) && (hbuf->size > 0))
  {
    hbuf->buf[hbuf->size - 1] = 0;
  }
  if ((hbuf->size > (SIZE_MAX / 2)) || (!hbuf->can_realloc))
  {
